mapper.select:
select count(*) as organ_number, category_id, slide_id from fr_annotation
contour_type='2'
AND slide_id in
#{id}
AND category_id = #{categoryId}
group by slide_id, category_id

select from fr_single_slide as ss left join fr_slide s on ss.slide_id = s.slide_id left join tb_image m on m.image_id = s.image_id
s.special_id = #{specialId, jdbcType=NUMERIC}
AND ss.category_id = #{categoryId, jdbcType=NUMERIC}
AND m.image_name like concat('%',#{imageName},'%')

select concat(min(cast( faf.results AS DECIMAL ( 18, 3 ) )),faf.unit,'-',max(cast( faf.results AS DECIMAL ( 18, 3 ) )),faf.unit)
from fr_single_slide fss
         left join fr_slide fs on fss.slide_id = fs.slide_id
    and fs.del_flag='0'
         left join fr_ai_forecast faf on faf.single_slide_id=fss.single_id
where fss.category_id = #{categoryId}
  and fs.special_id= #{specialId}
  and fs.group_code= #{groupCode}
group by faf.unit;
